"use strict";(self.webpackChunktu_cis_4398_docs_template=self.webpackChunktu_cis_4398_docs_template||[]).push([["1957"],{65026:function(e){e.exports=JSON.parse('{"project":{"title":"Clover","description":"CLOVER is an AI-powered coding assistant designed for educational use. It integrates with Visual Studio Code to provide real-time code suggestions, track user interactions, and analyze coding habits. By logging mistakes and offering contextual feedback, it helps novice programmers learn and avoid over-reliance on AI. A dashboard allows users to review their progress and coding behavior, making the assistant both a learning tool and a productivity aid.\\n","website":"https://clover.nickrucinski.com","documentation":"https://capstone-projects-2025-spring.github.io/project-copilot-clone-2/","source":"https://github.com/Capstone-Projects-2025-Spring/project-copilot-clone-2","demo":"https://www.youtube.com/watch?v=y990YPLQf2Q&t=725","tags":["ai","education","vscode-extension","research"],"semester":"Spring 2025","slug":"clover","members":["Jaime Nguyen","Antonio M Mongeluzi","Sophia Mettille","Nick Rucinski","Jack Martin"]},"routeSlug":"antonio-m-mongeluzi-clover","canonicalSlug":"clover"}')}}]);